import { useMemo, useState } from "react";
import "./App.css";

const fallbackRestaurants = [
  {
    id: "1",
    name: "Pizza Paradise",
    cuisine: "Italian",
    rating: 4.8,
    deliveryTime: "25-35 min",
    deliveryFee: 2.99,
    description: "Authentic Italian pizza with fresh ingredients.",
    image:
      "https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=900&q=80",
  },
  {
    id: "2",
    name: "Burger Boss",
    cuisine: "American",
    rating: 4.6,
    deliveryTime: "20-30 min",
    deliveryFee: 1.99,
    description: "Juicy burgers, crispy fries, and late-night comfort food.",
    image:
      "https://images.unsplash.com/photo-1568901346375-23c9450c58cd?auto=format&fit=crop&w=900&q=80",
  },
  {
    id: "3",
    name: "Sushi Supreme",
    cuisine: "Japanese",
    rating: 4.9,
    deliveryTime: "30-40 min",
    deliveryFee: 3.99,
    description: "Fresh sushi platters and beautifully balanced rolls.",
    image:
      "https://images.unsplash.com/photo-1579871494447-9811cf80d66c?auto=format&fit=crop&w=900&q=80",
  },
  {
    id: "4",
    name: "Green Garden",
    cuisine: "Healthy",
    rating: 4.5,
    deliveryTime: "20-30 min",
    deliveryFee: 1.49,
    description: "Colorful bowls, salads, and lighter feel-good meals.",
    image:
      "https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=900&q=80",
  },
];

function normalizeRestaurants(payload) {
  if (Array.isArray(payload)) {
    return payload;
  }

  if (Array.isArray(payload?.restaurants)) {
    return payload.restaurants;
  }

  if (Array.isArray(payload?.data)) {
    return payload.data;
  }

  return [];
}

function App() {
  const [username, setUsername] = useState("");
  const [token, setToken] = useState("");
  const [data, setData] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCuisine, setSelectedCuisine] = useState("All");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchedRestaurants = useMemo(() => normalizeRestaurants(data), [data]);
  const restaurants =
    fetchedRestaurants.length > 0 ? fetchedRestaurants : fallbackRestaurants;

  const cuisines = useMemo(() => {
    const mappedCuisines = restaurants
      .map((restaurant) => restaurant.cuisine || "Other")
      .filter(Boolean);

    return ["All", ...new Set(mappedCuisines)];
  }, [restaurants]);

  const filteredRestaurants = useMemo(() => {
    return restaurants.filter((restaurant) => {
      const name = (restaurant.name || "").toLowerCase();
      const cuisine = (restaurant.cuisine || "Other").toLowerCase();
      const description = (restaurant.description || "").toLowerCase();
      const query = searchTerm.toLowerCase();

      const matchesSearch =
        !query ||
        name.includes(query) ||
        cuisine.includes(query) ||
        description.includes(query);

      const matchesCuisine =
        selectedCuisine === "All" ||
        (restaurant.cuisine || "Other") === selectedCuisine;

      return matchesSearch && matchesCuisine;
    });
  }, [restaurants, searchTerm, selectedCuisine]);

  const handleSubmit = async () => {
    if (!username.trim() || !token.trim()) {
      setError("Enter both a username and token before fetching restaurants.");
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      const url = `http://localhost:8000/dataset/restaurants/${username}/${token}`;
      const response = await fetch(url);

      if (!response.ok) {
        throw new Error(`Request failed with status ${response.status}`);
      }

      const payload = await response.json();
      setData(payload);
    } catch (err) {
      console.error(err);
      setError("We couldn't load restaurants from the API, so the preview is showing fallback data.");
      setData(null);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="app-shell">
      <header className="topbar">
        <div className="brand-lockup">
          <div className="brand-mark">Q</div>
          <div>
            <p className="brand-kicker">Food Delivery</p>
            <h1>QuickEats</h1>
          </div>
        </div>
        <div className="topbar-copy">
          <span>Fast pickup</span>
          <span>Live filters</span>
          <span>Backend connected</span>
        </div>
      </header>

      <main>
        <section className="hero">
          <div className="hero-copy">
            <p className="eyebrow">Figma-inspired restaurant marketplace</p>
            <h2>Your favorite food, delivered with a cleaner frontend.</h2>
            <p className="hero-text">
              This layout brings the design into your existing React app while
              keeping the username and token fetch flow connected to the backend.
            </p>

            <div className="hero-search">
              <span className="search-icon">Search</span>
              <input
                type="text"
                placeholder="Search restaurants, cuisines, or dishes"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="hero-stats">
              <div>
                <strong>{restaurants.length}+</strong>
                <span>Restaurants</span>
              </div>
              <div>
                <strong>15 min</strong>
                <span>Avg pickup</span>
              </div>
              <div>
                <strong>4.8/5</strong>
                <span>Top rated</span>
              </div>
            </div>
          </div>

          <aside className="fetch-panel">
            <p className="panel-label">Connect your dataset</p>
            <h3>Load live restaurant data</h3>
            <p className="panel-copy">
              Enter your backend credentials to swap the preview cards with API
              results.
            </p>

            <label>
              Username
              <input
                type="text"
                placeholder="Enter username"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
              />
            </label>

            <label>
              Token
              <input
                type="text"
                placeholder="Enter token"
                value={token}
                onChange={(e) => setToken(e.target.value)}
              />
            </label>

            <button onClick={handleSubmit} disabled={isLoading}>
              {isLoading ? "Loading restaurants..." : "Fetch restaurants"}
            </button>

            <div className="panel-status">
              <span className={fetchedRestaurants.length ? "live" : "preview"}>
                {fetchedRestaurants.length ? "Live API data loaded" : "Showing preview data"}
              </span>
              {error ? <p>{error}</p> : null}
            </div>
          </aside>
        </section>

        <section className="filters-section">
          <div className="section-heading">
            <div>
              <p className="eyebrow">Browse restaurants</p>
              <h3>{filteredRestaurants.length} places available right now</h3>
            </div>
            <p className="section-copy">
              Filter by cuisine or use the search bar to narrow the list.
            </p>
          </div>

          <div className="cuisine-row">
            {cuisines.map((cuisine) => (
              <button
                key={cuisine}
                type="button"
                className={selectedCuisine === cuisine ? "chip active" : "chip"}
                onClick={() => setSelectedCuisine(cuisine)}
              >
                {cuisine}
              </button>
            ))}
          </div>
        </section>

        <section className="restaurant-grid">
          {filteredRestaurants.map((restaurant, index) => (
            <article className="restaurant-card" key={restaurant.id || index}>
              <div
                className="restaurant-media"
                style={{
                  backgroundImage: `linear-gradient(180deg, rgba(18, 23, 34, 0.02), rgba(18, 23, 34, 0.45)), url(${restaurant.image})`,
                }}
              >
                <span className="rating-badge">
                  {restaurant.rating || "4.7"} rating
                </span>
              </div>

              <div className="restaurant-body">
                <div className="restaurant-header">
                  <div>
                    <h4>{restaurant.name || "Restaurant"}</h4>
                    <p>{restaurant.cuisine || "Cuisine"}</p>
                  </div>
                  <span className="delivery-fee">
                    ${Number(restaurant.deliveryFee || 0).toFixed(2)}
                  </span>
                </div>

                <p className="restaurant-description">
                  {restaurant.description ||
                    "Fresh meals prepared quickly and delivered with care."}
                </p>

                <div className="restaurant-meta">
                  <span>{restaurant.deliveryTime || "25-35 min"}</span>
                  <span>Minimum order friendly</span>
                </div>
              </div>
            </article>
          ))}
        </section>

        {!filteredRestaurants.length ? (
          <section className="empty-state">
            <h3>No restaurants matched your filters.</h3>
            <p>Try another cuisine or clear the search term.</p>
          </section>
        ) : null}

        <section className="data-panel">
          <div className="section-heading">
            <div>
              <p className="eyebrow">API preview</p>
              <h3>Current response payload</h3>
            </div>
            <p className="section-copy">
              This stays visible so you can still inspect what the backend is returning.
            </p>
          </div>
          <pre>{JSON.stringify(data, null, 2) || "No live payload loaded yet."}</pre>
        </section>
      </main>
    </div>
  );
}

export default App;
